<template>
  <div class="detail">
    <van-tabs scrollspy sticky>
      <!-- 基本信息 -->
      <van-tab title="基本信息">
        <div class="msg">
          <!-- 轮播 -->
          <van-swipe
            class="banner"
            :autoplay="2000"
            v-show="detail.slider_image"
          >
            <van-swipe-item
              v-for="(image, index) in detail.slider_image"
              :key="index"
            >
              <img v-lazy="image" />
            </van-swipe-item>
          </van-swipe>
          <div class="descript">
            <p class="price">
              ￥{{ detail.price }}
              <label>￥{{ detail.vip_price }}</label>
              <img src="../assets/vip.png" alt="" />
            </p>
            <p>{{ detail.store_name }}</p>

            <ul class="bottom">
              <li>原价：{{ detail.ot_price }}</li>
              <li>销量：{{ detail.sales }} {{ detail.unit_name }}</li>
              <li>库存：{{ detail.stock }} {{ detail.unit_name }}</li>
            </ul>
          </div>
        </div>
      </van-tab>

      <!-- 推荐 -->
      <van-tab title="推荐">
        <div class="tRecom">
          <p class="title">精品推荐</p>
          <div class="recom">
            <recom-list v-for="a in recom" :key="a.id" :a="a"></recom-list>
          </div>
        </div>
      </van-tab>

      <!-- 详情 -->
      <van-tab title="详情" v-show="detail.description">
        <div class="de">
          <p class="title">详情信息</p>
          <div class="descri" v-html="detail.description"></div>
        </div>
      </van-tab>
    </van-tabs>

    <!-- 商品导航 -->
    <van-goods-action>
      <van-goods-action-icon icon="chat-o" text="客服" color="#ee0a24" />
      <van-goods-action-icon
        icon="cart-o"
        text="购物车"
        @click="$router.push('/cart')"
        :badge="count"
      />
      <van-goods-action-button
        type="warning"
        text="加入购物车"
        @click="show = true"
      />
      <van-goods-action-button
        type="danger"
        text="立即购买"
        @click="show = true"
      />
    </van-goods-action>

    <!-- 选择商品规格 sku -->
    <van-sku
      v-model="show"
      :sku="sku"
      :goods="goods"
      :goods-id="goodsId"
      @buy-clicked="buyClicked"
      @add-cart="addCart"
    />
  </div>
</template>

<script>
import RecomList from "@/components/RecomList";
export default {
  components: { RecomList },
  props: ["_id"],
  data() {
    return {
      detail: "",
      recom: [],
      show: false,
      uniId: "",
      count: 0,
      cId: "",
      confirmMsg: "",
      sku: {
        tree: [
          {
            k: "颜色", //属性名称
            k_id: "1", //属性的ID值 唯一 在当前产品里面唯一
            v: [
              //颜色属性可用值列表
              {
                id: "30349", //属性ID
                name: "红色", //属性名
                //属性图片，默认只有第一行属性有
                imgUrl: "https://b.yzcdn.cn/vant/sku/shoes-1.png",
              },
              {
                id: "1215",
                name: "白色",
                imgUrl: "https://b.yzcdn.cn/vant/sku/shoes-1.png",
              },
              {
                id: "1216",
                name: "棕色",
                imgUrl: "https://b.yzcdn.cn/vant/sku/shoes-1.png",
              },
            ],
            k_s: "s1", //属性的k_s值 对应list里面组合键名
          },
          {
            k: "尺寸",
            k_id: "2",
            v: [
              {
                id: "1193",
                name: "30码",
              },
              {
                id: "1194",
                name: "40码",
              },
            ],
            k_s: "s2",
            count: 2,
          },
        ],
        // 所有 sku 的组合列表，如下是：白色1、白色2、天蓝色1、天蓝色2
        list: [
          {
            id: 2300,
            price: 500,
            s1: "1216",
            s2: "1193",
            stock_num: 100,
            goods_id: 123123,
          },
          {
            id: 2259,
            price: 120, //价格
            s1: "1215", //对应属性列表里面 k_s 等于s1的属性id值
            s2: "1193",
            stock_num: 20, //库存
            goods_id: 946755, //产品ID
          },
          {
            id: 2260,
            price: 110,
            s1: "1215",
            s2: "1194",
            stock_num: 2,
            goods_id: 946755,
          },
          {
            id: 2257,
            price: 130,
            s1: "30349",
            s2: "1193",
            stock_num: 40,
            goods_id: 946755,
          },
          {
            id: 2258,
            price: 100,
            s1: "30349",
            s2: "1194",
            stock_num: 50,
            goods_id: 946755,
          },
        ],
        price: "500.00",
        stock_num: 227, // 商品总库存
        none_sku: false, // 是否无规格商品
        hide_stock: false, // 是否隐藏剩余库存
      },
      goods: {},
      goodsId: 1,
    };
  },
  created() {
    this.axios.get("/api/cart/count").then((d) => {
      this.count = d.data.data.count;
    });
    this.axios.get("/api/product/detail/" + this._id).then((d) => {
      // 转换数据
      let arrs = d.data.data.productAttr;
      let listValue = d.data.data.productValue;
      this.goodsId = this._id;
      // this.goods=d.data.data.storeInfo;
      //sku 数据转换
      let id = 1;
      let idobj = {};
      let ssk = 1;
      this.sku.list = [];
      if (listValue[Object.keys(listValue)[0]]) {
        //获取产品属性里面第一个值默认图片
        this.goods.picture = listValue[Object.keys(listValue)[0]].image;
      }

      //循环产品属性 组装购物车 属性tree
      this.sku.tree = arrs.map((atr, ads) => {
        let va = atr.attr_value.map((at, index) => {
          id++;
          idobj[at.attr] = id;
          let attrs = {
            id: id,
            name: at.attr,
          };
          if (ads < 1) {
            attrs.imgUrl = listValue[Object.keys(listValue)[index]].image;
          }

          return attrs;
        });
        var ks = "s" + ssk;
        ssk++;
        return {
          k: atr.attr_name,
          k_id: atr.attr_name,
          v: va,
          k_s: ks,
        };
      });
      //循环产品属性组合,组装sku 列表
      for (let key in listValue) {
        let v = listValue[key];
        let keys = key.split(",");
        this.sku.list.push({
          id: v.unique,
          price: v.price * 100, //价格
          s1: idobj[keys[0]],
          s2: idobj[keys[1]],
          stock_num: v.stock, //库存
          goods_id: v.product_id,
          imgUrl: v.image,
        });
      }
      this.detail = d.data.data.storeInfo;
      // console.log("this.detail=>", this.detail);
    });
    // 推荐商品
    this.axios.get("/api/index").then((da) => {
      this.recom = da.data.data.info.bastList.slice(0, 9);
      // console.log(this.recom);
    });
  },
  // 监听_id的变化
  watch: {
    _id(newVal) {
      this.axios.get("api/product/detail/" + newVal).then((d) => {
        // 转换数据
        let arrs = d.data.data.productAttr;
        let listValue = d.data.data.productValue;
        this.goodsId = this._id;
        //sku 数据转换
        let id = 1;
        let idobj = {};
        let ssk = 1;
        this.sku.list = [];
        if (listValue[Object.keys(listValue)[0]]) {
          //获取产品属性里面第一个值默认图片
          this.goods.picture = listValue[Object.keys(listValue)[0]].image;
        }
        //循环产品属性 组装购物车 属性tree
        this.sku.tree = arrs.map((atr, ads) => {
          let va = atr.attr_value.map((at, index) => {
            id++;
            idobj[at.attr] = id;
            let attrs = {
              id: id,
              name: at.attr,
            };
            if (ads < 1) {
              attrs.imgUrl = listValue[Object.keys(listValue)[index]].image;
            }

            return attrs;
          });
          var ks = "s" + ssk;
          ssk++;
          return {
            k: atr.attr_name,
            k_id: atr.attr_name,
            v: va,
            k_s: ks,
          };
        });
        //循环产品属性组合,组装sku 列表
        for (let key in listValue) {
          let v = listValue[key];
          let keys = key.split(",");
          this.sku.list.push({
            id: v.unique,
            price: v.price * 100, //价格
            s1: idobj[keys[0]],
            s2: idobj[keys[1]],
            stock_num: v.stock, //库存
            goods_id: v.product_id,
            imgUrl: v.image,
          });
        }
        this.detail = d.data.data.storeInfo;
      });
    },
  },
  methods: {
    // 加购
    addCart(e) {
      // 购物车数量
      this.axios.get("/api/cart/count").then((d) => {
        this.count = d.data.data.count;
      });
      //  加购数据
      this.axios.post("/api/cart/add", {
        cartNum: 1,
        new: 0,
        productId: this.detail.id,
        uniqueId: e.selectedSkuComb.id,
      });
      this.show = false;
    },
    // 购买
    buyClicked(e) {
      // 先通过加购获取cartId
      this.axios
        .post("/api/cart/add", {
          cartNum: 1,
          new: 0,
          productId: this.detail.id,
          uniqueId: e.selectedSkuComb.id,
        })
        .then((d) => {
          // 加购完了传递cartId到订单详情页面
          console.log(d.data.data);
          this.cId = d.data.data.cartId;
           this.$router.push({
                path: "/ConfirmDetail",
                query: {cId: this.cId},
              });
            
        });
    },
  },
};
</script>

<style lang="less" >
.detail {
  font-size: 16px;

  .banner {
    width: 100%;
    img {
      width: 100%;
      margin: 0 auto;
    }
  }
  .van-swipe {
    .van-swipe__indicators {
      .van-swipe__indicator--active {
        background-color: #fff;
        opacity: 1;
      }
    }
  }
  // 基本信息
  .descript {
    padding: 0 5px;
    margin-bottom: 50px;
    .price {
      position: relative;
      font-size: 18px;
      font-weight: bolder;
      color: #fa877b;
      label {
        font-size: 14px;
        color: #333;
        margin: 0 5px;
      }
      img {
        position: absolute;
        top: 5px;
      }
    }
    .bottom {
      display: flex;
      justify-content: space-between;
      font-size: 12px;
      color: #666;
    }
  }
  //推荐
  .tRecom {
    width: 100%;
    margin-bottom: 50px;
    .recom {
      text-align: center;
      display: flex;
      justify-content: space-between;
      flex-wrap: wrap;
      width: 100%;
      font-size: 14px;
      .box {
        width: 30%;
        //    height: 220px;
        margin: 5px;
        img {
          width: 100%;
          height: 140px;
          border-radius: 10px;
        }
        p.shopName {
          white-space: nowrap;
          overflow: hidden;
          text-overflow: ellipsis;
        }
      }
    }
  }
  .title {
    text-align: center;
    font-weight: bolder;
    font-size: 18px;
  }
  .de {
    width: 100%;
    overflow: hidden;
    background-color: rgb(250, 250, 247);
    .descri {
      img {
        display: block !important;
        width: 375px !important;
      }
    }
  }
}
</style>